function md2h(s){let h=s;h=h.replace(/```(\w*)\n([\s\S]*?)```/g,'<pre><code>$2</code></pre>');h=h.replace(/`([^`]+)`/g,'<code>$1</code>');h=h.replace(/^### (.*$)/gm,'<h3>$1</h3>');h=h.replace(/^## (.*$)/gm,'<h2>$1</h2>');h=h.replace(/^# (.*$)/gm,'<h1>$1</h1>');h=h.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>');h=h.replace(/\*(.*?)\*/g,'<em>$1</em>');h=h.replace(/^> (.*$)/gm,'<blockquote>$1</blockquote>');h=h.replace(/^---$/gm,'<hr>');h=h.replace(/^\|(.+)\|$/gm,m=>{const c=m.split('|').filter(x=>x.trim());if(c.every(x=>/^[\s\-:]+$/.test(x)))return'';return'<tr>'+c.map(x=>'<td>'+x.trim()+'</td>').join('')+'</tr>'});h=h.replace(/(<tr>[\s\S]*?<\/tr>\n?)+/g,'<table>$&</table>');h=h.replace(/^[\*\-] (.*$)/gm,'<li>$1</li>');h=h.replace(/^\d+\. (.*$)/gm,'<li>$1</li>');h=h.replace(/(<li>[\s\S]*?<\/li>\n?)+/g,'<ul>$&</ul>');h=h.replace(/\n\n/g,'</p><p>');h=h.replace(/\n/g,'<br>');return'<p>'+h+'</p>'}
async function gen(){
  const i=document.getElementById('iB').value.trim();
  if(at.type==='upload'){if(!window.uploadedImage){alert('Please upload an image first!');return;}if(at.needsPrompt&&!i){alert('Please describe the edit!');return;}}
  else if(!i)return;
  const requiredCredits=at.type==='text'?2:(at.cost||10);
  const isFreeT=at.free===true;
  if(!isFreeT&&window.userPlan!=='pro'&&(window.userCredits||0)<requiredCredits){
    document.getElementById('oA').innerHTML='<div style="padding:50px 20px;text-align:center"><div style="font-size:48px;margin-bottom:16px">⚠️</div><div style="color:#fff;font-size:16px;font-weight:800;margin-bottom:8px">Insufficient Credits</div><div style="color:#94a3b8;font-size:13px;margin-bottom:16px;max-width:400px;margin-left:auto;margin-right:auto">This tool requires <strong style="color:#ef4444">'+requiredCredits+' credits</strong> but you only have <strong style="color:#f59e0b">'+(window.userCredits||0)+' credits</strong>.<br/><br/>Upgrade to Pro for <strong style="color:#10b981">500 credits/month</strong>.</div><a href="/pricing.html" style="display:inline-block;background:linear-gradient(135deg,#3b82f6,#06b6d4);color:#fff;padding:12px 28px;border-radius:10px;text-decoration:none;font-size:14px;font-weight:800">🚀 Upgrade to Pro — $9.99/mo</a></div>';
    return;
  }
  if(!isFreeT&&window.userPlan==='pro'&&(window.userCredits||0)<requiredCredits){
    document.getElementById('oA').innerHTML='<div style="padding:50px 20px;text-align:center"><div style="font-size:48px;margin-bottom:16px">⚠️</div><div style="color:#fff;font-size:16px;font-weight:800;margin-bottom:8px">Monthly Credits Exhausted</div><div style="color:#94a3b8;font-size:13px;margin-bottom:16px">All 500 credits used this month. Refresh next month or contact support for top-up.</div><a href="mailto:support@taskbasehq.com" style="display:inline-block;background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.1);color:#fff;padding:12px 28px;border-radius:10px;text-decoration:none;font-size:14px;font-weight:800">📧 Contact Support</a></div>';
    return;
  }
  const b=document.getElementById('gB');b.innerHTML='⏳ Generating...';b.disabled=true;
  document.getElementById('oA').innerHTML='<div style="padding:50px 20px;text-align:center"><div style="width:36px;height:36px;border:3px solid rgba(59,130,246,0.15);border-top-color:#3b82f6;border-radius:50%;animation:spin .7s linear infinite;margin:0 auto 14px"></div><div style="color:#3b82f6;font-size:13px;font-weight:700">AI generating...</div><div style="color:#475569;font-size:11px;margin-top:3px">'+(at.type==='image'?'10-30 seconds':at.type==='voice'?'5-10 seconds':'5-15 seconds')+'</div></div>';
  try{
    let url=API_URL,body={};
    if(at.type==='image'){url=IMAGE_API;body={prompt:(at.promptPrefix||'')+i,plan:window.userPlan||'free'};}
    else if(at.type==='voice'){url=VOICE_API;body={text:i};}
    else if(at.type==='upload'){
      if(!window.uploadedImage){throw new Error('Please upload an image first!');}
      url=at.api;body={image:window.uploadedImage};
      if(at.needsPrompt){if(!i)throw new Error('Please describe the edit!');body.prompt=i;}
      else if(at.optionalPrompt&&i){body.replacePrompt=i;}
      else if(at.extraPrompt){body.prompt=at.extraPrompt;}
    }
    else{
      let promptInput=i;
      if(at.textUpload&&window.extractedText){
        let extractedSafe=window.extractedText;
        if(extractedSafe.length>25000)extractedSafe=extractedSafe.substring(0,25000)+'\n\n[... document truncated ...]';
        promptInput='Existing document content:\n\n---\n'+extractedSafe+'\n---\n\nUser instruction: '+i;
      }
      const finalPrompt=at.pr(promptInput);
      body={prompt:finalPrompt.length>29500?finalPrompt.substring(0,29500):finalPrompt};
    }
    const r=await fetch(url,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});
    let d;
    try {
      const txt = await r.text();
      try {
        d = JSON.parse(txt);
      } catch(parseErr) {
        // Server returned HTML/text instead of JSON (likely timeout or crash)
        if(r.status===504||r.status===524) throw new Error('Request timed out. Try shorter input or try again.');
        if(r.status===500) throw new Error('Server error. Please try again in a moment.');
        if(r.status===429) throw new Error('Rate limit. Please wait a moment and try again.');
        throw new Error('Server returned invalid response. Status: '+r.status+'. Please try again.');
      }
    } catch(e) {
      if(e.message.includes('Request timed out')||e.message.includes('Rate limit')||e.message.includes('Server error')||e.message.includes('Server returned')){throw e;}
      throw new Error('Network error: '+e.message);
    }
    if(!r.ok){throw new Error(d?.error||'API Error: '+r.status);}
    if(d.error)throw new Error(d.error);
    if(at.type==='image'||at.type==='upload'){
      co=d.image||'';
      const lbl=at.type==='upload'?'✨ Edited Image':'🎨 Generated Image';
      const qBadge = d.quality?'<span style="background:'+(d.quality.includes('4K')?'rgba(168,85,247,0.15);color:#a855f7':d.quality.includes('HD')?'rgba(245,158,11,0.15);color:#f59e0b':'rgba(59,130,246,0.15);color:#3b82f6')+';font-size:10px;font-weight:800;padding:3px 8px;border-radius:6px;margin-left:8px">'+d.quality+'</span>':'';
      document.getElementById('oA').innerHTML='<div class="ot"><div class="ol">'+lbl+qBadge+'</div><div class="os"><span>Stability AI</span></div></div><div class="oc" style="text-align:center"><img src="data:image/png;base64,'+co+'" style="max-width:100%;border-radius:12px;box-shadow:0 8px 30px rgba(0,0,0,0.3)" /></div>';
      document.getElementById('dlB').style.display='';
    }else if(at.type==='voice'){
      co=d.audio||'';
      document.getElementById('oA').innerHTML='<div class="ot"><div class="ol">🎙️ Generated Voice</div><div class="os"><span>ElevenLabs</span></div></div><div class="oc" style="text-align:center"><audio controls style="width:100%;margin:20px 0"><source src="data:audio/mpeg;base64,'+co+'" type="audio/mpeg"></audio></div>';
      document.getElementById('dlB').style.display='';
    }else{
      co=d.text||'No response.';
      const w=co.split(/\s+/).length,c=co.length,rt=Math.ceil(w/200);
      document.getElementById('oA').innerHTML='<div class="ot"><div class="ol">📄 AI Output</div><div class="os"><span>📝 '+w+' words</span><span>📖 '+rt+' min</span><span>🔤 '+c+' chars</span></div></div><div class="oc">'+md2h(co)+'</div>';
      ['cpB','clB'].forEach(id=>document.getElementById(id).style.display='');
      renderExportButtons();
    }
    if(window.trackUsage)window.trackUsage(at.type==='text'?2:(at.cost||10));
    if(window.saveToLibrary&&window.userPlan==='pro'){
      const libType=at.type==='text'?'text':at.type==='voice'?'voice':'image';
      window.saveToLibrary({tool:at.id,toolName:at.name,type:libType,input:i,output:co,cost:at.type==='text'?2:(at.cost||10)});
    }
  }catch(e){document.getElementById('oA').innerHTML='<div style="padding:40px 20px;text-align:center"><div style="font-size:36px;margin-bottom:12px">⚠️</div><div style="color:#ef4444;font-size:13px;font-weight:700">'+e.message+'</div><div style="color:#475569;font-size:11px;margin-top:6px">Please try again</div></div>';}
  b.innerHTML='⚡ Generate';b.disabled=false;
}
function cpO(){navigator.clipboard?.writeText(co);const b=document.getElementById('cpB');b.innerHTML='✅ Copied!';setTimeout(()=>b.innerHTML='📋 Copy',2000)}
function dlO(format){
  if(at.type==='image'||at.type==='upload'){
    const a=document.createElement('a');a.href='data:image/png;base64,'+co;a.download='taskbasehq-image-'+Date.now()+'.png';a.click();return;
  }
  if(at.type==='voice'){
    const a=document.createElement('a');a.href='data:audio/mpeg;base64,'+co;a.download='taskbasehq-voice-'+Date.now()+'.mp3';a.click();return;
  }
  const fmt=format||'txt';
  const baseName=at.name.replace(/\s+/g,'-').toLowerCase()+'-'+Date.now();
  if(fmt==='pdf'){window.exportPDF(co,baseName,at.name);}
  else if(fmt==='docx'){window.exportDocx(co,baseName,at.name);}
  else if(fmt==='xlsx'){window.exportXlsx(co,baseName);}
  else if(fmt==='csv'){window.exportCsv(co,baseName);}
  else if(fmt==='html'){const blob=new Blob([co],{type:'text/html'});const u=URL.createObjectURL(blob);const a=document.createElement('a');a.href=u;a.download=baseName+'.html';a.click();URL.revokeObjectURL(u);}
  else{const b=new Blob([co],{type:'text/plain'});const u=URL.createObjectURL(b);const a=document.createElement('a');a.href=u;a.download=baseName+'.txt';a.click();URL.revokeObjectURL(u);}
}
window.exportPDF=function(text,filename,title){
  if(!window.jspdf){alert('PDF library loading... please try again');return;}
  const{jsPDF}=window.jspdf;
  const doc=new jsPDF({unit:'pt',format:'letter'});
  const margin=50,maxWidth=512,lineHeight=14;
  let y=margin;
  doc.setFont('helvetica','bold');doc.setFontSize(18);
  doc.text(title||'Document',margin,y);y+=30;
  doc.setFont('helvetica','normal');doc.setFontSize(11);doc.setTextColor(0);
  const cleanText=text.replace(/#{1,3}\s/g,'').replace(/\*\*(.*?)\*\*/g,'$1').replace(/\*(.*?)\*/g,'$1').replace(/`([^`]+)`/g,'$1').replace(/^\|.*\|$/gm,'').replace(/^[-*]\s/gm,'• ').replace(/\n{3,}/g,'\n\n');
  const lines=doc.splitTextToSize(cleanText,maxWidth);
  lines.forEach(line=>{
    if(y>740){doc.addPage();y=margin;}
    doc.text(line,margin,y);y+=lineHeight;
  });
  doc.save(filename+'.pdf');
}
window.exportDocx=function(text,filename,title){
  const docxLib=window.docx||window.Docx;
  if(!docxLib){alert('Word library failed to load. Please refresh and try again.');return;}
  try{
    const{Document,Paragraph,TextRun,Packer,HeadingLevel}=docxLib;
    const cleanText=text.replace(/[*#`\[\]_~]/g,'');
    const paragraphs=cleanText.split('\n').map(line=>{
      if(line.trim()==='')return new Paragraph({});
      return new Paragraph({children:[new TextRun({text:line,size:22})]});
    });
    const doc=new Document({sections:[{properties:{},children:[new Paragraph({text:title||'Document',heading:HeadingLevel.HEADING_1}),new Paragraph({}), ...paragraphs]}]});
    Packer.toBlob(doc).then(blob=>{
      if(window.saveAs){window.saveAs(blob,filename+'.docx');}
      else{const u=URL.createObjectURL(blob);const a=document.createElement('a');a.href=u;a.download=filename+'.docx';document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(u);}
    }).catch(err=>{console.error('DOCX error:',err);alert('Word export failed. Try PDF or Text instead.');});
  }catch(e){console.error('DOCX error:',e);alert('Word export failed: '+e.message);}
}
window.exportXlsx=function(text,filename){
  if(!window.XLSX){alert('Excel library loading... please try again');return;}
  const lines=text.split('\n').filter(l=>l.trim());
  const data=lines.map(line=>{
    if(line.includes('|'))return line.split('|').map(c=>c.trim()).filter(Boolean);
    if(line.includes('\t'))return line.split('\t');
    return[line];
  });
  const ws=window.XLSX.utils.aoa_to_sheet(data);
  const wb=window.XLSX.utils.book_new();
  window.XLSX.utils.book_append_sheet(wb,ws,'Sheet1');
  window.XLSX.writeFile(wb,filename+'.xlsx');
}
window.exportCsv=function(text,filename){
  const lines=text.split('\n').filter(l=>l.trim());
  const csv=lines.map(line=>{
    if(line.includes('|'))return line.split('|').map(c=>'"'+c.trim().replace(/"/g,'""')+'"').filter(c=>c!=='""').join(',');
    return'"'+line.replace(/"/g,'""')+'"';
  }).join('\n');
  const blob=new Blob([csv],{type:'text/csv'});
  const u=URL.createObjectURL(blob);
  const a=document.createElement('a');a.href=u;a.download=filename+'.csv';a.click();URL.revokeObjectURL(u);
}
